// Fetch active agents + name aliases from Supabase
const apikey = 'YOUR_SUPABASE_ANON_KEY';
const base = 'https://bcibmmbxrjfiulofserv.supabase.co/rest/v1';
const hdr = { 'apikey': apikey };

const [roster, aliases] = await Promise.all([
  this.helpers.httpRequest({ method: 'GET', url: base + '/agents?select=name,tier,site,crm_agent_id&is_active=eq.true', headers: hdr, json: true }),
  this.helpers.httpRequest({ method: 'GET', url: base + '/agent_name_aliases?select=canonical_name,crm_name', headers: hdr, json: true }),
]);

if (!roster || roster.length === 0) {
  return [{ json: { error: true, message: 'No active agents found in Supabase' } }];
}

// Build alias map: canonical_name → crm_name (how the CRM dropdown shows the name)
const nameAliases = {};
for (const a of (aliases || [])) {
  nameAliases[a.canonical_name] = a.crm_name;
}

const targetAgents = roster.map(a => a.name);
const agentTiers = {};
const agentSites = {};
const agentCrmIds = {};
for (const a of roster) {
  agentTiers[a.name] = a.tier;
  agentSites[a.name] = a.site === 'AUS' ? 'ATX' : 'CLT';
  if (a.crm_agent_id) agentCrmIds[a.name] = a.crm_agent_id;
}

return [{
  json: {
    targetAgents,
    agentTiers,
    agentSites,
    agentCrmIds,
    nameAliases,
    agentCount: roster.length,
    apifyBody: JSON.stringify({
      crmUsername: 'YOUR_CRM_USERNAME',
      crmPassword: 'YOUR_CRM_PASSWORD',
      targetAgents,
      agentTiers,
      agentCrmIds,
      nameAliases,
      requestDelay: 1500
    })
  }
}];

// Fetch Apify dataset and extract pipeline compliance data
const runStatus = $input.first().json;
const datasetId = runStatus?.data?.defaultDatasetId;
const runId = runStatus?.data?.id || 'unknown';

if (!datasetId) {
  return [{ json: { error: true, message: 'No defaultDatasetId. runId=' + runId } }];
}

const token = 'YOUR_APIFY_API_TOKEN';

async function fetchDataset(dsId, attempt) {
  const url = `https://api.apify.com/v2/datasets/${dsId}/items?token=${token}`;
  const raw = await this.helpers.httpRequest({
    method: 'GET', url, encoding: 'utf-8', returnFullResponse: false, timeout: 60000,
    headers: { 'Accept': 'application/json' },
  });
  let parsed = raw;
  if (typeof raw === 'string') {
    try { parsed = JSON.parse(raw); } catch (e) {
      throw new Error(`JSON parse failed (attempt ${attempt}): ${raw.substring(0, 200)}`);
    }
  }
  return parsed;
}

let datasetItems;
let lastErr;
for (let attempt = 1; attempt <= 3; attempt++) {
  try {
    datasetItems = await fetchDataset.call(this, datasetId, attempt);
    if (Array.isArray(datasetItems) && datasetItems.length > 0) break;
    if (attempt < 3) await new Promise(r => setTimeout(r, 10000));
  } catch (err) {
    lastErr = err;
    if (attempt < 3) await new Promise(r => setTimeout(r, 10000));
  }
}

if (!datasetItems || !Array.isArray(datasetItems) || datasetItems.length === 0) {
  // Try parsing single object (pipeline_compliance type)
  if (datasetItems && typeof datasetItems === 'object' && !Array.isArray(datasetItems)) {
    datasetItems = [datasetItems];
  } else {
    return [{ json: { error: true, message: 'Dataset empty after 3 attempts. ' + (lastErr?.message || ''), datasetId, runId } }];
  }
}

// The pipeline scraper pushes a single object with _type: 'pipeline_compliance'
const pipelineItem = datasetItems.find(item => item._type === 'pipeline_compliance');

if (!pipelineItem) {
  return [{ json: { error: true, message: 'No pipeline_compliance item found in dataset', datasetId, runId } }];
}

// Ensure scrape_date falls on a weekday (match daily scrape convention)
let sd = pipelineItem.scrape_date;
if (sd) {
  const [sy,sm,sdd] = sd.split('-').map(Number);
  const sdt = new Date(sy, sm-1, sdd);
  const dow = sdt.getDay();
  if (dow === 0) sdt.setDate(sdt.getDate() - 2);
  else if (dow === 6) sdt.setDate(sdt.getDate() - 1);
  sd = sdt.toISOString().slice(0,10);
}

// Build map of scraped agent names to their confirmed CRM IDs
const confirmedIds = {};
for (const a of (pipelineItem.agents || [])) {
  if (a.agent_name && a.agent_id_crm) confirmedIds[a.agent_name] = a.agent_id_crm;
}

return [{
  json: {
    scrape_date: sd,
    agents: pipelineItem.agents || [],
    summary: pipelineItem.summary || {},
    agentSites: $node['Fetch Agent Roster'].json.agentSites || {},
    crmDropdown: pipelineItem.crmDropdown || [],
    confirmedCrmIds: confirmedIds
  }
}];

// Build Slack compliance report
const payload = $node['Fetch Dataset & Parse'].json;
const agents = payload.agents || [];
const agentSites = payload.agentSites || {};
const scrapeDate = payload.scrape_date;
const summary = payload.summary || {};

const fmt = (n) => '$' + Math.round(n).toLocaleString();

// Tier grouping
const tiers = { T1: [], T2: [], T3: [] };
for (const a of agents) {
  const tier = a.tier || 'T3';
  if (!tiers[tier]) tiers[tier] = [];
  tiers[tier].push(a);
}

// Sort each tier by total_stale DESC
for (const tier of Object.keys(tiers)) {
  tiers[tier].sort((a, b) => (b.total_stale || 0) - (a.total_stale || 0));
}

// Top offenders (top 10 by total_stale)
const allSorted = [...agents].sort((a, b) => (b.total_stale || 0) - (a.total_stale || 0));
const topOffenders = allSorted.slice(0, 10);

// Build the offender list
let offenderList = '';
for (let i = 0; i < topOffenders.length; i++) {
  const a = topOffenders[i];
  if (a.total_stale <= 0) continue;
  const site = agentSites[a.agent_name] || 'CLT';
  const emoji = a.total_stale > 30 ? ':rotating_light:' : a.total_stale > 15 ? ':warning:' : ':eyes:';
  offenderList += `${emoji} *${a.agent_name}* (${a.tier}/${site}): ${a.total_stale} stale | ${a.past_due_follow_ups} past-due | ${a.new_leads} new | ${a.call_queue_count} queue | ${fmt(a.revenue_at_risk)} at risk\n`;
}

if (!offenderList) offenderList = ':white_check_mark: No agents with stale leads today!';

// Per-tier summary
let tierSummary = '';
for (const tier of ['T1', 'T2', 'T3']) {
  const ta = tiers[tier] || [];
  if (ta.length === 0) continue;
  const stale = ta.reduce((s, a) => s + (a.total_stale || 0), 0);
  const risk = ta.reduce((s, a) => s + (a.revenue_at_risk || 0), 0);
  const pastDue = ta.reduce((s, a) => s + (a.past_due_follow_ups || 0), 0);
  const newLeads = ta.reduce((s, a) => s + (a.new_leads || 0), 0);
  const flagged = ta.filter(a => (a.total_stale || 0) > 10).length;
  tierSummary += `*${tier}* (${ta.length} agents): ${stale} stale leads | ${pastDue} past-due | ${newLeads} untouched new | ${flagged} flagged | ${fmt(risk)} at risk\n`;
}

const totalStale = summary.total_stale_leads || agents.reduce((s, a) => s + (a.total_stale || 0), 0);
const totalRisk = summary.total_revenue_at_risk || agents.reduce((s, a) => s + (a.revenue_at_risk || 0), 0);
const totalRecovery = summary.total_projected_recovery || agents.reduce((s, a) => s + (a.projected_recovery || 0), 0);
const totalPastDue = agents.reduce((s, a) => s + (a.past_due_follow_ups || 0), 0);
const totalNewLeads = agents.reduce((s, a) => s + (a.new_leads || 0), 0);

const message = {
  text: 'Pipeline Compliance Audit - ' + scrapeDate,
  blocks: [
    { type: 'header', text: { type: 'plain_text', text: ':mag: Pipeline Compliance Audit \u2014 ' + scrapeDate, emoji: true } },
    { type: 'section', text: { type: 'mrkdwn', text: '*' + agents.length + ' agents* audited  |  *' + totalStale + '* total stale leads  |  *' + fmt(totalRisk) + '* revenue at risk' } },
    { type: 'divider' },
    { type: 'section', text: { type: 'mrkdwn', text: '*:bar_chart: Tier Breakdown*\n' + tierSummary } },
    { type: 'divider' },
    { type: 'section', text: { type: 'mrkdwn', text: '*:rotating_light: Top Stale Lead Offenders*\n' + offenderList } },
    { type: 'divider' },
    { type: 'section', fields: [
      { type: 'mrkdwn', text: '*Total Past Due*\n:red_circle: ' + totalPastDue + ' leads' },
      { type: 'mrkdwn', text: '*Untouched New Leads*\n:large_orange_diamond: ' + totalNewLeads + ' leads' },
      { type: 'mrkdwn', text: '*Revenue at Risk*\n:money_with_wings: ' + fmt(totalRisk) },
      { type: 'mrkdwn', text: '*Projected Recovery*\n:chart_with_upwards_trend: ' + fmt(totalRecovery) + '/mo' }
    ]},
    { type: 'context', elements: [{ type: 'mrkdwn', text: 'Pipeline audit date: ' + scrapeDate + '  |  SLA: T1=3d, T2=5d, T3=5d, New=1d  |  Recovery assumes 12% conversion on recycled leads' }] }
  ]
};

return [{ json: message }];

// Backfill CRM agent IDs from scraped results into agents table
const payload = $node['Fetch Dataset & Parse'].json;
const agents = payload.agents || [];
const apikey = 'YOUR_SUPABASE_ANON_KEY';
const base = 'https://bcibmmbxrjfiulofserv.supabase.co/rest/v1';
let updated = 0;

for (const a of agents) {
  if (!a.agent_name || !a.agent_id_crm) continue;
  try {
    await this.helpers.httpRequest({
      method: 'PATCH',
      url: base + '/agents?name=eq.' + encodeURIComponent(a.agent_name),
      headers: {
        'apikey': apikey,
        'Authorization': 'Bearer ' + apikey,
        'Content-Type': 'application/json',
        'Prefer': 'return=minimal'
      },
      body: JSON.stringify({ crm_agent_id: a.agent_id_crm }),
      json: true
    });
    updated++;
  } catch (e) {
    // continue on error
  }
}

return [{ json: { message: `Backfilled CRM IDs for ${updated}/${agents.length} agents` } }];
